#include <stdio.h>
#include <stdlib.h>
#define MAX_N 50000

int heights[MAX_N];
int graph[MAX_N][MAX_N];
int visited[MAX_N];
int count;

void dfs(int city, int parent, int l, int r, int current_count) {
    visited[city] = 1;
    int child_count = 0;
    for (int i = 0; i < MAX_N; i++) {
        if (graph[city][i] == 1 && visited[i] == 0) {
            child_count++;
            dfs(i, city, l, r, current_count + (heights[city] < heights[i] && heights[i] > heights[parent]));
        }
    }
    if (child_count == 0) {
        if (current_count >= l && current_count <= r) {
            count++;
        }
    }
    visited[city] = 0;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, l, r;
        scanf("%d %d %d", &n, &l, &r);
        for (int i = 0; i < n; i++) {
            scanf("%d", &heights[i]);
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                graph[i][j] = 0;
            }
        }
        for (int i = 0; i < n - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            graph[u - 1][v - 1] = 1;
            graph[v - 1][u - 1] = 1;
        }
        count = 0;
        for (int i = 0; i < n; i++) {
            dfs(i, -1, l, r, 0);
        }
        printf("%d\n", count);
    }
    return 0;
}

