int visited[MAX_N];
int count;

void dfs(int city, int parent, int l, int r, int current_count) {
    visited[city] = 1;
    for (int i = 0; i < graph[city].size(); i++) {
        if (visited[graph[city][i]] == 0) {
            dfs(graph[city][i], city, l, r, current_count + (heights[city] < heights[graph[city][i]] && heights[graph[city][i]] > heights[parent]));
        }
    }
    if (graph[city].size() == 1 && parent != -1) {
        if (current_count >= l && current_count <= r) {
            count++;
        }
    }
    visited[city] = 0;
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n, l, r;
        cin >> n >> l >> r;
        for (int i = 0; i < n; i++) {
            cin >> heights[i];
        }
        for (int i = 0; i < n; i++) {
            graph[i].clear();
        }
        for (int i = 0; i < n - 1; i++) {
            int u, v;
            cin >> u >> v;
            graph[u - 1].push_back(v - 1);
            graph[v - 1].push_back(u - 1);
