            for (int i = 0; i < n; i++) {
                graph[i] = new ArrayList<>();
            }
            for (int i = 0; i < n - 1; i++) {
                int u = scanner.nextInt() - 1;
                int v = scanner.nextInt() - 1;
                graph[u].add(v);
                graph[v].add(u);
            }
            visited = new int[n];
            count = 0;
            for (int i = 0; i < n; i++) {
                dfs(i, -1, l, r, 0);
            }
            System.out.println(count);
        }
    }
